    def roche_limit_ispat(self):
        """
        ROCHE LIMITI (SENTEZ-27): Gel-git ParÃƒÂ§alanma SÃ„Â±nÃ„Â±rÃ„Â±nÃ„Â±n Bilimsel Ã„Â°spatÃ„Â±.
        FormÃƒÂ¼l: d = R_M * (2 * rho_M / rho_m)^(1/3)
        """
        BOLD, GOLD, GREEN, ENDC = "\033[1m", "\033[33m", "\033[32m", "\033[0m"
        R_Earth = 6371.0
        rho_Earth = 5.51
        rho_Moon = 3.34

        # SÃ„Â±vÃ„Â± Roche Limiti (Fluid)
        d_fluid = R_Earth * 2.44 * (rho_Earth / rho_Moon) ** (1/3)
        # KatÃ„Â± Roche Limiti (Rigid)
        d_rigid = R_Earth * 1.26 * (rho_Earth / rho_Moon) ** (1/3)

        print(f"  {BOLD}[BÃƒâ€“LÃƒÅ“M 6.5] ROCHE LÃ„Â°MÃ„Â°TÃ„Â° (GEL-GÃ„Â°T PARÃƒâ€¡ALANMA SINIRI) Ã„Â°SPATI{ENDC}")
        print(f"      DÃƒÂ¼nya YarÃ„Â±ÃƒÂ§apÃ„Â± (R): {R_Earth} km")
        print(f"      DÃƒÂ¼nya YoÃ„Å¸unluÃ„Å¸u (rho_M): {rho_Earth} g/cmÃ‚Â³")
        print(f"      Ay YoÃ„Å¸unluÃ„Å¸u (rho_m): {rho_Moon} g/cmÃ‚Â³")
        print(f"      {GOLD}SÃ„Â±vÃ„Â± Roche Limiti (2.44R):{ENDC} {d_fluid:.1f} km")
        print(f"      {GOLD}KatÃ„Â± Roche Limiti (1.26R):{ENDC} {d_rigid:.1f} km")
        print(f"      {GREEN}-> SONUÃƒâ€¡: SimÃƒÂ¼lasyonun {self.const.ROCHE_LIMIT_EARTH} km'lik sÃ„Â±nÃ„Â±rÃ„Â±, sÃ„Â±vÃ„Â± Ay'Ã„Â±n parÃƒÂ§alanma eÃ…Å¸iÃ„Å¸idir!{ENDC}")

