    def get_db_findings(self):
        findings = {}
        if not os.path.exists(self.db_path):
            return findings
        try:
            conn = sqlite3.connect(self.db_path)
            rows = conn.execute(
                "SELECT kaynak, veri FROM KarTopu ORDER BY id DESC LIMIT 10"
            ).fetchall()
            for k, v in rows:
                key = k.split(":")[-1].strip()
                try:
                    findings[key] = float(v)
                except ValueError:
                    findings[key] = v
            conn.close()
        except Exception:
            pass
        return findings


