    def dunya_capi_oruntusu(self):
        carpim = self.GEOIT_FARK * self.OMURGA * self.GEOIT_TOPLAM
        cap_izdusumu = carpim / 10.0
        fiziksel_cap_kodu = cap_izdusumu - self.GEOIT_FARK
        sapma = abs(fiziksel_cap_kodu - self.GERCEK_EKVATOR_CAPI)
        return carpim, cap_izdusumu, fiziksel_cap_kodu, sapma

    def hacim_1333_oruntusu(self):
        return self.GEOIT_TOPLAM / self.OMURGA, (self.OMURGA + self.GEOIT_FARK) / self.OMURGA

    def bukulme_1666_oruntusu(self):
        return (self.GEOIT_TOPLAM + self.GEOIT_FARK) / self.OMURGA

