        surtunme_kutlesi = self.UZAY_SABITI - self.ZAMAN_SABITI
        sapma_yuzdesi = abs(surtunme_kutlesi - self.HIGGS_KUTLE_GEV) / self.HIGGS_KUTLE_GEV * 100
