class Sentez26_GeodesicWarpMatrix:
    """
    Yeryuzundeki kutsal geometrik noktalarin (Hatay, Kailash, Giza, Stonehenge)
    arasindaki mesafe ve aci oruntullerini Base-11 sistemi icinde analiz eder.
    """

    NODES = [
        (36.300, 36.200, "Hatay (Antakya)"),
        (31.130, 29.979, "Giza Piramidi"),
        (31.049, 81.313, "Kailash Dagi"),
        (51.179, -1.826, "Stonehenge"),
        (27.175, 78.042, "Taj Mahal"),
        (29.979, 31.134, "Giza Sfenks"),
        (21.420, 39.826, "Kabe (Mekke)"),
        (41.008, 28.980, "Ayasofya"),
        (13.412, 103.867, "Angkor Wat"),
        (37.971, 23.727, "Parthenon"),
        (47.557, 10.750, "Neuschwanstein"),
    ]

    EARTH_RADIUS_KM = 6371.0

    def __init__(self):
        self._results = {}
        self._distance_matrix = []

    def _haversine(self, lat1, lon1, lat2, lon2):
        """Iki nokta arasindaki buyuk daire mesafesini hesapla (km)."""
        from math import radians, sin, cos, sqrt, atan2

        lat1, lon1, lat2, lon2 = map(radians, [lat1, lon1, lat2, lon2])
        dlat = lat2 - lat1
        dlon = lon2 - lon1
        a = sin(dlat/2)**2 + cos(lat1) * cos(lat2) * sin(dlon/2)**2
        c = 2 * atan2(sqrt(a), sqrt(1-a))
        return self.EARTH_RADIUS_KM * c

    def compute_distance_matrix(self):
        """Tum nodalar arasi mesafe matrisini hesapla."""
        n = len(self.NODES)
        matrix = [[0.0] * n for _ in range(n)]

        for i in range(n):
            for j in range(i+1, n):
                d = self._haversine(
                    self.NODES[i][0], self.NODES[i][1],
                    self.NODES[j][0], self.NODES[j][1]
                )
                matrix[i][j] = d
                matrix[j][i] = d

        self._distance_matrix = matrix
        return matrix

    def _to_base11(self, num):
        if num == 0:
            return "0"
        digits = []
        n = abs(num)
        while n > 0:
            digits.append(str(n % 11))
            n //= 11
        return ''.join(reversed(digits))

    def find_base11_resonances(self):
        """Mesafe matrisindeki Base-11 rezonanslarini bul."""
        resonances = []

        for i in range(len(self.NODES)):
            for j in range(i+1, len(self.NODES)):
                d = self._distance_matrix[i][j]
                d_int = int(round(d))

                b11 = self._to_base11(d_int)

                patterns = ['666', '111', '333', '1111', '11']
                for p in patterns:
                    if p in b11:
                        resonances.append({
                            'from': self.NODES[i][2],
                            'to': self.NODES[j][2],
                            'distance_km': d,
                            'base11': b11,
                            'pattern': p,
                        })
                        break

                if d_int % 11 == 0:
                    resonances.append({
                        'from': self.NODES[i][2],
                        'to': self.NODES[j][2],
                        'distance_km': d,
                        'base11': b11,
                        'pattern': 'DIV_11',
                    })

        self._results['resonances'] = resonances
        return resonances

    def compute_angular_harmonics(self):
        """Nodalarin enlem/boylamlari uzerinden 11-harmonik analizi."""
        from math import sin, cos, radians

        harmonics = []
        for lat, lon, name in self.NODES:
            s_lat = sin(radians(lat))
            c_lat = cos(radians(lat))
            h11_lat = sin(radians(11 * lat))
            h11_lon = cos(radians(11 * lon))
            h33_lat = sin(radians(33 * lat))

            score = abs(h11_lat) + abs(h11_lon) + abs(h33_lat)

            harmonics.append({
                'name': name,
                'lat': lat, 'lon': lon,
                'h11_lat': h11_lat,
                'h11_lon': h11_lon,
                'h33_lat': h33_lat,
                'composite_score': score,
            })

        harmonics.sort(key=lambda x: x['composite_score'], reverse=True)
        self._results['angular_harmonics'] = harmonics
        return harmonics

    def compute_hatay_kailash_axis(self):
        """Hatay-Kailash ekseninin ozel analizini yap."""
        hatay = self.NODES[0]
        kailash = self.NODES[2]

        distance = self._haversine(hatay[0], hatay[1], kailash[0], kailash[1])
        lat_diff = abs(hatay[0] - kailash[0])
        lon_diff = abs(hatay[1] - kailash[1])

        deviation_from_6666 = abs(distance - 6666)
        pct_deviation = (deviation_from_6666 / 6666) * 100

        lat_ratio_to_11 = lat_diff / 11

        axis_data = {
            'distance_km': distance,
            'target_km': 6666,
            'deviation_km': deviation_from_6666,
            'deviation_pct': pct_deviation,
            'lat_diff': lat_diff,
            'lon_diff': lon_diff,
            'lat_ratio_to_11': lat_ratio_to_11,
            'is_locked': deviation_from_6666 < 100,
        }

        self._results['hatay_kailash_axis'] = axis_data
        return axis_data

    def run_all(self):
        """Sentez-26 tam analiz suitini calistir."""
        print("")
        print("=" * 80)
        print("  SENTEZ-26: GEODESIK WARP MATRISI & KOZMIK HARMONIKLER")
        print("=" * 80)

        # 1. Mesafe Matrisi
        print(f"\n  [1] MESAFE MATRISI ({len(self.NODES)} Nodal Nokta)")
        self.compute_distance_matrix()

        pairs = []
        for i in range(len(self.NODES)):
            for j in range(i+1, len(self.NODES)):
                pairs.append((self._distance_matrix[i][j], self.NODES[i][2], self.NODES[j][2]))
        pairs.sort()

        print("      En Yakin 3 Cift:")
        for d, n1, n2 in pairs[:3]:
            print(f"        {n1} <-> {n2}: {d:.1f} km")
        print("      En Uzak 3 Cift:")
        for d, n1, n2 in pairs[-3:]:
            print(f"        {n1} <-> {n2}: {d:.1f} km")

        # 2. Base-11 Rezonanslar
        resonances = self.find_base11_resonances()
        print("\n  [2] BASE-11 REZONANS TESPITI")
        print(f"      Toplam Rezonans         : {len(resonances)}")
        for r in resonances[:8]:
            print(f"      [{r['pattern']:6s}] {r['from'][:20]:20s} <-> {r['to'][:20]:20s} = {r['distance_km']:.0f}km (B11: {r['base11']})")

        # 3. Hatay-Kailash Eksen
        axis = self.compute_hatay_kailash_axis()
        print("\n  [3] HATAY-KAILASH EKSEN KILIDI")
        print(f"      Gercek Mesafe           : {axis['distance_km']:.1f} km")
        print(f"      Hedef (6666 km)         : {axis['target_km']} km")
        print(f"      Sapma                   : {axis['deviation_km']:.1f} km ({axis['deviation_pct']:.2f}%)")
        print(f"      Enlem Farki             : {axis['lat_diff']:.3f} derece")
        print(f"      Eksen Kilidi            : {'AKTIF' if axis['is_locked'] else 'PASIF'}")

        # 4. Acisal Harmonikler
        harmonics = self.compute_angular_harmonics()
        print("\n  [4] 11-HARMONIK ACISAL ANALIZ")
        for h in harmonics[:5]:
            print(f"      {h['name']:25s}: H11={h['h11_lat']:+.4f} H33={h['h33_lat']:+.4f} Skor={h['composite_score']:.4f}")

        print(f"\n  {'='*80}")
        print(f"  SENTEZ-26 TAMAMLANDI | Rezonans Sayisi: {len(resonances)}")
        print(f"  {'='*80}")

        return self._results


