class Sentez27_TimeSeriesAnomalyDetector:
    """
    Tarihsel olaylarin zaman serisi uzerindeki Base-11 oruntusunu analiz eder.
    """

    HISTORICAL_EVENTS = [
        (-9048, "Tufan (Noah's Flood)"),
        (-7000, "Catalhoyuk Kurulumu"),
        (-5508, "Bizans Takvimi Baslangici"),
        (-3500, "Sumer Uygarlik Baslangici"),
        (-3100, "Misir Birlesik Krallik"),
        (-2600, "Giza Piramitleri"),
        (-1800, "Hz. Ibrahim"),
        (-1200, "Troya Savasi"),
        (-563, "Buda Dogumu"),
        (-551, "Konfucyus Dogumu"),
        (0, "Hz. Isa (Milat)"),
        (622, "Hz. Muhammed Hicret"),
        (1054, "Yengec Bulutsusu Supernova"),
        (1347, "Kara Olum (Veba)"),
        (1453, "Istanbul Fethi"),
        (1492, "Amerika Kesfi"),
        (1666, "Londra Buyuk Yangini"),
        (1687, "Newton Principia"),
        (1776, "ABD Bagimsizlik"),
        (1789, "Fransiz Devrimi"),
        (1905, "Einstein Ozel Gorelilik"),
        (1945, "Atom Bombasi"),
        (1969, "Ay'a Inis"),
        (1983, "Observer Dogumu"),
        (2001, "9/11 Olayi"),
        (2012, "Higgs Bozonu Kesfi"),
        (2020, "COVID-19 Pandemisi"),
        (2042, "Faz-3 Baslangici"),
        (2063, "Terminal Shutdown"),
    ]

    def __init__(self):
        self._results = {}

    def compute_intervals(self):
        """Ardisik olaylar arasi zaman araligini hesapla."""
        intervals = []
        events = self.HISTORICAL_EVENTS

        for i in range(1, len(events)):
            delta = events[i][0] - events[i-1][0]
            intervals.append({
                'from': events[i-1][1],
                'to': events[i][1],
                'from_year': events[i-1][0],
                'to_year': events[i][0],
                'delta': delta,
                'delta_mod11': delta % 11,
                'delta_div11': delta // 11,
            })

        self._results['intervals'] = intervals
        return intervals

    def find_11_pattern_intervals(self):
        """11'e bolunebilen veya 11'in katlari olan araliklari bul."""
        intervals = self._results.get('intervals', self.compute_intervals())

        pattern_hits = []
        for iv in intervals:
            d = iv['delta']
            if d % 11 == 0:
                pattern_hits.append({**iv, 'pattern': 'MOD_11'})
            elif d % 33 == 0:
                pattern_hits.append({**iv, 'pattern': 'MOD_33'})
            elif d % 111 == 0:
                pattern_hits.append({**iv, 'pattern': 'MOD_111'})
            elif str(d).count('1') >= 2:
                pattern_hits.append({**iv, 'pattern': 'DIGIT_11'})

        self._results['pattern_hits'] = pattern_hits

        total = len(intervals)
        hits = len(pattern_hits)
        expected = total * (1/11)
        ratio = hits / expected if expected > 0 else 0

        self._results['pattern_ratio'] = ratio
        self._results['pattern_expected'] = expected

        return pattern_hits

    def compute_tufan_terminal_span(self):
        """Tufan (-9048) -> Terminal (2063) = 11111 yil hipotezini test et."""
        tufan_year = -9048
        terminal_year = 2063
        span = terminal_year - tufan_year

        decimal_11111 = 11111
        is_exact = (span == decimal_11111)
        deviation = abs(span - decimal_11111)

        base11_of_11111 = 1*11**4 + 1*11**3 + 1*11**2 + 1*11 + 1

        tufan_data = {
            'tufan_year': tufan_year,
            'terminal_year': terminal_year,
            'span_years': span,
            'target_11111': decimal_11111,
            'is_exact': is_exact,
            'deviation': deviation,
            'base11_of_11111': base11_of_11111,
        }

        self._results['tufan_terminal'] = tufan_data
        return tufan_data

    def compute_countdown_2063(self):
        """Simdiden 2063'e kac gun kaldigi."""
        from datetime import datetime

        now = datetime.now()
        terminal = datetime(2063, 12, 21, 0, 0, 0)
        delta = terminal - now

        days_left = delta.days
        hours_left = delta.seconds // 3600

        sim_years_left = days_left / 363

        days_mod11 = days_left % 11
        days_div11 = days_left // 11

        countdown = {
            'now': now.isoformat(),
            'terminal': terminal.isoformat(),
            'days_left': days_left,
            'hours_left': hours_left,
            'sim_years_left': sim_years_left,
            'days_mod11': days_mod11,
            'days_div11': days_div11,
        }

        self._results['countdown'] = countdown
        return countdown

    def run_all(self):
        """Sentez-27 tam analiz suitini calistir."""
        print("")
        print("=" * 80)
        print("  SENTEZ-27: ZAMAN SERISI ANOMALI DEDEKTORU & 2063 COUNTDOWN")
        print("=" * 80)

        # 1. Araliklar
        intervals = self.compute_intervals()
        print(f"\n  [1] TARIHSEL ARALIKLAR ({len(intervals)} aralik)")

        # 2. 11-Oruntu
        hits = self.find_11_pattern_intervals()
        print("\n  [2] BASE-11 ORUNTU ANALIZI")
        print(f"      Toplam Aralik           : {len(intervals)}")
        print(f"      11-Oruntu Isaretleri    : {len(hits)}")
        print(f"      Beklenen (rastgele)     : {self._results['pattern_expected']:.1f}")
        print(f"      Oran (gozlenen/beklenen): {self._results['pattern_ratio']:.2f}x")

        for h in hits[:5]:
            print(f"      [{h['pattern']:8s}] {h['from_year']:>5d} -> {h['to_year']:>5d} = {h['delta']:>5d} yil | {h['from'][:25]} -> {h['to'][:25]}")

        # 3. Tufan-Terminal
        tt = self.compute_tufan_terminal_span()
        print("\n  [3] TUFAN -> TERMINAL SPAN")
        print(f"      Tufan                   : {tt['tufan_year']}")
        print(f"      Terminal                : {tt['terminal_year']}")
        print(f"      Aralik                  : {tt['span_years']} yil")
        print(f"      Hedef                   : {tt['target_11111']} (11111)")
        print(f"      Tam Eslesme             : {'EVET' if tt['is_exact'] else 'HAYIR'}")
        print(f"      Sapma                   : {tt['deviation']} yil")

        # 4. 2063 Countdown
        cd = self.compute_countdown_2063()
        print("\n  [4] 2063 TERMINAL COUNTDOWN")
        print(f"      Simdi                   : {cd['now'][:19]}")
        print(f"      Terminal                : {cd['terminal'][:10]}")
        print(f"      Kalan Gun               : {cd['days_left']:,}")
        print(f"      Sim-Yil (363g)          : {cd['sim_years_left']:.2f}")
        print(f"      Kalan Gun mod 11        : {cd['days_mod11']}")
        print(f"      Kalan 11-Blok           : {cd['days_div11']:,}")

        print(f"\n  {'='*80}")
        print(f"  SENTEZ-27 TAMAMLANDI | Tufan->2063 = {tt['span_years']} yil")
        print(f"  {'='*80}")

        return self._results


