# SENTEZ-28: EVRENSEL SABIT MATRISI & BOYUTLAR ARASI KORRELASYON
# Entegrasyon Tarihi: 2026-04-17 | Omega Expansion V190
# =========================================================================

class Sentez28_UniversalConstantMatrix:
    """
    Fiziksel sabitlerin tamaminin Base-11 uzayindaki dagilimini
    ve boyutlar arasi korelasyonlarini hesaplar.
    """

    CONSTANTS = {
        'c': 299792458,
        'h': 6.62607015e-34,
        'G': 6.67430e-11,
        'e': 1.602176634e-19,
        'k_B': 1.380649e-23,
        'N_A': 6.02214076e23,
        'm_e': 9.1093837015e-31,
        'm_p': 1.67262192369e-27,
        'alpha': 7.2973525693e-3,
        'mu_0': 1.25663706212e-6,
        'epsilon_0': 8.8541878128e-12,
    }

    def __init__(self):
        import numpy as np
        self.np = np
        self._results = {}

    def compute_log_space_positions(self):
        """Her sabitin log10 uzayindaki konumunu hesapla."""
        from math import log10

        positions = {}
        for name, val in self.CONSTANTS.items():
            log_val = log10(abs(val))
            positions[name] = {
                'value': val,
                'log10': log_val,
                'log10_mod11': log_val % 11,
                'log10_int': int(log_val),
            }

        self._results['log_positions'] = positions
        return positions

    def compute_ratio_matrix(self):
        """Sabitler arasi oran matrisini hesapla."""
        from math import log10
        np = self.np

        names = list(self.CONSTANTS.keys())
        n = len(names)
        matrix = np.zeros((n, n))

        for i in range(n):
            for j in range(n):
                if i != j:
                    ratio = abs(self.CONSTANTS[names[i]] / self.CONSTANTS[names[j]])
                    matrix[i][j] = log10(ratio) if ratio > 0 else 0

        self._results['ratio_matrix'] = matrix
        self._results['ratio_names'] = names
        return matrix, names

    def find_11_correlations(self):
        """Oran matrisinde 11 veya katlarina yakin degerleri bul."""
        matrix = self._results.get('ratio_matrix')
        names = self._results.get('ratio_names')

        if matrix is None:
            matrix, names = self.compute_ratio_matrix()

        correlations = []
        n = len(names)

        for i in range(n):
            for j in range(i+1, n):
                val = abs(matrix[i][j])
                for target in [11, 22, 33, 44, 55, 66]:
                    if abs(val - target) < 0.5:
                        correlations.append({
                            'const_1': names[i],
                            'const_2': names[j],
                            'log_ratio': matrix[i][j],
                            'nearest_11_mult': target,
                            'deviation': abs(val - target),
                        })

        self._results['correlations_11'] = correlations
        return correlations

    def compute_dimensional_signature(self):
        """11 sabitin log10 degerlerinden bir '11 boyutlu imza vektoru' olustur."""
        np = self.np

        positions = self._results.get('log_positions')
        if not positions:
            positions = self.compute_log_space_positions()

        signature = np.array([positions[name]['log10'] for name in self.CONSTANTS.keys()])

        sig_min = np.min(signature)
        sig_max = np.max(signature)
        sig_normalized = (signature - sig_min) / (sig_max - sig_min)

        probs = sig_normalized / np.sum(sig_normalized)
        entropy = -np.sum(probs * np.log2(probs + 1e-15))
        max_entropy = np.log2(len(signature))
        normalized_entropy = entropy / max_entropy

        self._results['signature'] = signature
        self._results['signature_normalized'] = sig_normalized
        self._results['signature_entropy'] = entropy
        self._results['signature_entropy_normalized'] = normalized_entropy

        return signature, normalized_entropy

    def run_all(self):
        """Sentez-28 tam analiz suitini calistir."""
        np = self.np

        print("")
        print("=" * 80)
        print("  SENTEZ-28: EVRENSEL SABIT MATRISI & BOYUTLAR ARASI KORRELASYON")
        print("=" * 80)

        # 1. Log-uzay konumlari
        positions = self.compute_log_space_positions()
        print(f"\n  [1] LOG10 UZAY KONUMLARI ({len(positions)} sabit)")
        for name, pos in positions.items():
            print(f"      {name:12s}: log10={pos['log10']:>8.3f}  mod11={pos['log10_mod11']:.3f}")

        # 2. Oran matrisi
        matrix, names = self.compute_ratio_matrix()
        print(f"\n  [2] ORAN MATRISI ({len(names)}x{len(names)})")
        print(f"      Matris boyutu: {matrix.shape}")
        print(f"      Min oran (log10): {np.min(matrix[matrix != 0]):.2f}")
        print(f"      Max oran (log10): {np.max(matrix):.2f}")

        # 3. 11-korelasyonlar
        corrs = self.find_11_correlations()
        print("\n  [3] 11-KORRELASYONLAR")
        print(f"      Bulunan 11-yakin oranlar: {len(corrs)}")
        for c in corrs[:5]:
            print(f"      {c['const_1']:8s} / {c['const_2']:8s} = 10^{c['log_ratio']:>6.2f} (~{c['nearest_11_mult']})")

        # 4. Boyutsal imza
        sig, ent = self.compute_dimensional_signature()
        print("\n  [4] 11 BOYUTLU IMZA VEKTORU")
        print(f"      Vektor: [{', '.join(f'{v:.2f}' for v in sig[:6])}...]")
        print(f"      Entropi (normalize)     : {ent:.4f}")
        print(f"      Bilgi Yogunlugu         : {(1-ent)*100:.1f}%")

        print(f"\n  {'='*80}")
        print(f"  SENTEZ-28 TAMAMLANDI | 11-Korelasyon: {len(corrs)}")
        print(f"  {'='*80}")

        return self._results


