class Sentez30_FibonacciBase11Convergence:
    """
    Fibonacci dizisinin Base-11 ozelliklerini analiz eder.

    Hipotezler:
    - Altin Oran (phi = 1.618...) Base-11'de ozel bir gosterime sahiptir
    - Fibonacci sayilarinin mod 11 dagilimi periyodiktir (Pisano periyodu)
    - Pisano(11) = 10 (Fibonacci mod 11'in periyodu)
    - Bu periyodiklik simulasyonun zaman yapisini kodlar
    """

    PHI = (1 + 5**0.5) / 2  # Altin Oran = 1.6180339887...
    PSI = (1 - 5**0.5) / 2  # Eslenik = -0.6180339887...

    def __init__(self):
        self._results = {}
        self._fib_cache = {}

    def _to_base11(self, num):
        if num == 0:
            return "0"
        digits = []
        n = abs(num)
        while n > 0:
            digits.append(str(n % 11))
            n //= 11
        return ''.join(reversed(digits))

    def generate_fibonacci(self, count=111):
        """Fibonacci dizisinin ilk N elemanini uret."""
        fib = [0, 1]
        for i in range(2, count):
            fib.append(fib[-1] + fib[-2])
        self._results['fibonacci'] = fib
        return fib

    def compute_pisano_period(self, modulus=11):
        """Pisano periyodunu hesapla: Fibonacci mod m'nin periyodu."""
        prev, curr = 0, 1
        for i in range(1, modulus * modulus + 1):
            prev, curr = curr, (prev + curr) % modulus
            if prev == 0 and curr == 1:
                self._results['pisano_period'] = i
                return i
        self._results['pisano_period'] = -1
        return -1

    def analyze_fibonacci_base11(self):
        """Fibonacci sayilarinin Base-11 ozelliklerini analiz et."""
        fib = self._results.get('fibonacci', self.generate_fibonacci())

        analysis = []
        for i, f in enumerate(fib[:55]):  # Ilk 55 (= 5 * 11)
            b11 = self._to_base11(f)
            mod11 = f % 11
            digit_sum = sum(int(d) for d in b11 if d.isdigit())

            has_pattern = any(p in b11 for p in ['111', '666', '333'])

            analysis.append({
                'index': i,
                'value': f,
                'base11': b11,
                'mod11': mod11,
                'digit_sum': digit_sum,
                'ds_mod11': digit_sum % 11,
                'has_pattern': has_pattern,
            })

        self._results['fib_analysis'] = analysis
        return analysis

    def compute_golden_ratio_base11(self):
        """Altin Oranin Base-11 gosterimini hesapla."""
        phi = self.PHI

        # Tam kisim: 1
        integer_part = int(phi)
        fractional = phi - integer_part

        # Kesirli kismi Base-11'e donustur (11 basamak hassasiyet)
        b11_digits = [str(integer_part), '.']
        frac = fractional
        for _ in range(11):
            frac *= 11
            digit = int(frac)
            b11_digits.append(str(digit))
            frac -= digit

        b11_string = ''.join(b11_digits)

        # phi^11 hesapla
        phi_pow_11 = phi ** 11  # = 322.997...
        b11_phi11 = self._to_base11(int(round(phi_pow_11)))

        golden_data = {
            'phi_decimal': phi,
            'phi_base11': b11_string,
            'phi_pow_11': phi_pow_11,
            'phi_pow_11_int': int(round(phi_pow_11)),
            'phi_pow_11_b11': b11_phi11,
        }

        self._results['golden_ratio'] = golden_data
        return golden_data

    def compute_fib_mod11_distribution(self):
        """Fibonacci mod 11 dagilimini hesapla."""
        fib = self._results.get('fibonacci', self.generate_fibonacci())

        distribution = [0] * 11
        for f in fib:
            distribution[f % 11] += 1

        # Entropi hesabi
        total = sum(distribution)
        from math import log2
        entropy = 0
        for count in distribution:
            if count > 0:
                p = count / total
                entropy -= p * log2(p)

        max_entropy = log2(11)
        uniformity = entropy / max_entropy

        dist_data = {
            'distribution': distribution,
            'entropy': entropy,
            'max_entropy': max_entropy,
            'uniformity': uniformity,
        }

        self._results['mod11_distribution'] = dist_data
        return dist_data

    def find_fibonacci_11_convergences(self):
        """Fibonacci dizisinde 11 ile iliskili yakinsakliklari bul."""
        fib = self._results.get('fibonacci', self.generate_fibonacci())

        convergences = []

        for i in range(2, len(fib)):
            ratio = fib[i] / fib[i-1] if fib[i-1] > 0 else 0
            deviation_from_phi = abs(ratio - self.PHI)

            # Ratio * 11'in tam sayiya yakinligi
            ratio_times_11 = ratio * 11
            nearest_int = round(ratio_times_11)
            deviation_11 = abs(ratio_times_11 - nearest_int)

            if deviation_11 < 0.01 or deviation_from_phi < 1e-10:
                convergences.append({
                    'index': i,
                    'fib_n': fib[i],
                    'ratio': ratio,
                    'phi_deviation': deviation_from_phi,
                    'ratio_x11': ratio_times_11,
                    'deviation_11': deviation_11,
                })

        self._results['convergences'] = convergences
        return convergences

    def run_all(self):
        """Sentez-30 tam analiz suitini calistir."""
        print("")
        print("=" * 80)
        print("  SENTEZ-30: FIBONACCI-BASE11 YAKINSAKLIK MATRISI")
        print("=" * 80)

        # 1. Fibonacci Uretimi
        fib = self.generate_fibonacci(111)
        print("\n  [1] FIBONACCI DIZISI (N=111)")
        print(f"      F(11)                   : {fib[11]} (B11: {self._to_base11(fib[11])})")
        print(f"      F(22)                   : {fib[22]} (B11: {self._to_base11(fib[22])})")
        print(f"      F(33)                   : {fib[33]} (B11: {self._to_base11(fib[33])})")
        print(f"      F(55)                   : {fib[55]}")
        print(f"      F(110)                  : {fib[110]}")

        # 2. Pisano Periyodu
        pisano = self.compute_pisano_period(11)
        print("\n  [2] PISANO PERIYODU (mod 11)")
        print(f"      Pisano(11)              : {pisano}")
        print(f"      Anlam: Fib mod 11 her {pisano} sayida tekrarlar")

        # 3. Base-11 Analizi
        analysis = self.analyze_fibonacci_base11()
        print("\n  [3] FIBONACCI BASE-11 ANALIZI (ilk 55)")
        patterned = [a for a in analysis if a['has_pattern']]
        print(f"      Oruntu iceren sayilar   : {len(patterned)}")
        for a in analysis[10:16]:
            print(f"      F({a['index']:2d}) = {a['value']:>10d} -> B11: {a['base11']:>12s} mod11={a['mod11']}")

        # 4. Altin Oran Base-11
        golden = self.compute_golden_ratio_base11()
        print("\n  [4] ALTIN ORAN BASE-11 GOSTERIMI")
        print(f"      phi (decimal)           : {golden['phi_decimal']:.10f}")
        print(f"      phi (Base-11)           : {golden['phi_base11']}")
        print(f"      phi^11                  : {golden['phi_pow_11']:.3f}")
        print(f"      phi^11 (B11)            : {golden['phi_pow_11_b11']}")

        # 5. Mod-11 Dagilimi
        dist = self.compute_fib_mod11_distribution()
        print("\n  [5] FIBONACCI MOD-11 DAGILIMI")
        print(f"      Dagilim                 : {dist['distribution']}")
        print(f"      Entropi                 : {dist['entropy']:.4f}")
        print(f"      Tekduzelik              : {dist['uniformity']:.4f}")

        # 6. Yakinsakliklar
        convs = self.find_fibonacci_11_convergences()
        print("\n  [6] 11-YAKINSAKLIKLAR")
        print(f"      Bulunan                 : {len(convs)}")
        for c in convs[:5]:
            print(f"      F({c['index']:2d}): ratio={c['ratio']:.10f} x11={c['ratio_x11']:.6f} dev={c['deviation_11']:.6f}")

        print(f"\n  {'='*80}")
        print(f"  SENTEZ-30 TAMAMLANDI | Pisano(11)={pisano} | Yakinsaklik: {len(convs)}")
        print(f"  {'='*80}")

        return self._results


